import React, { useState, useMemo } from 'react';

const th = {
  bg: '#0a0a0a', surface: '#111', surfaceAlt: '#1a1a1a',
  border: '#2a2a2a', text: '#fafafa', muted: '#a1a1aa', dim: '#52525b',
  blue: '#38bdf8', green: '#a3e635', purple: '#a78bfa',
  yellow: '#fbbf24', pink: '#f472b6', orange: '#fb923c',
};

const INIT = [
  [[[2, 4], [6, 8]], [[-1, 3], [0, 2]]],
  [[[10, 20], [30, 40]], [[0.5, -0.5], [1.5, -1.5]]],
];
const clone = d => JSON.parse(JSON.stringify(d));

const computeNorm = (slice, gamma, beta) => {
  const eps = 1e-5;
  const f = slice.flat();
  const mean = f.reduce((a, b) => a + b, 0) / f.length;
  const variance = f.reduce((a, b) => a + (b - mean) ** 2, 0) / f.length;
  const std = Math.sqrt(variance + eps);
  const normalized = slice.map(r => r.map(v => (v - mean) / std));
  const output = normalized.map(r => r.map(v => gamma * v + beta));
  return { mean, variance, std, normalized, output };
};

const valBg = (v, range) => {
  const t = Math.min(Math.abs(v) / Math.max(range, 0.01), 1) * 0.4;
  return v >= 0 ? `rgba(56,189,248,${t})` : `rgba(244,114,182,${t})`;
};

export default function App() {
  const [data, setData] = useState(clone(INIT));
  const [sel, setSel] = useState([0, 0]);
  const [gamma, setGamma] = useState(1.0);
  const [beta, setBeta] = useState(0.0);

  const allResults = useMemo(() =>
    data.map(b => b.map(c => computeNorm(c, gamma, beta))),
    [data, gamma, beta]
  );

  const slice = data[sel[0]][sel[1]];
  const result = allResults[sel[0]][sel[1]];
  const maxIn = Math.max(...slice.flat().map(Math.abs), 0.1);
  const maxOut = Math.max(...result.output.flat().map(Math.abs), 0.1);

  const editCell = (r, c, e) => {
    e.preventDefault();
    const delta = e.shiftKey ? -1 : 1;
    const d = clone(data);
    d[sel[0]][sel[1]][r][c] = Math.round((d[sel[0]][sel[1]][r][c] + delta) * 10) / 10;
    setData(d);
  };

  const reset = () => { setData(clone(INIT)); setGamma(1); setBeta(0); setSel([0, 0]); };

  const sameNorm = useMemo(() => {
    const n00 = allResults[0][0].normalized.flat();
    const n10 = allResults[1][0].normalized.flat();
    return n00.every((v, i) => Math.abs(v - n10[i]) < 0.001);
  }, [allResults]);

  const getInsight = () => {
    if (result.variance < 0.001) {
      return { icon: '!', color: th.orange, text: 'All spatial values are nearly identical, so variance is ~0. The epsilon prevents division by zero, but normalization amplifies tiny differences.' };
    }
    if (sel[0] === 0 && sel[1] === 0 && sameNorm) {
      return { icon: '*', color: th.yellow, text: 'Try selecting B1,Ch0: it has inputs 5x larger [10,20,30,40] but the SAME normalized output! Instance Norm removes scale differences between instances.' };
    }
    if (sel[0] === 1 && sel[1] === 0 && sameNorm) {
      return { icon: '!', color: th.green, text: 'Same normalized output as B0,Ch0! Despite 5x larger inputs, the relative pattern is identical. This is WHY Instance Norm works for style transfer: it removes per-instance scale (style) while preserving structure (content).' };
    }
    if (Math.abs(gamma) < 0.05) {
      return { icon: '~', color: th.pink, text: 'With gamma near 0, all outputs collapse to beta. The network can "turn off" normalization for channels that don\'t need it.' };
    }
    if (Math.abs(gamma - 1) < 0.05 && Math.abs(beta) < 0.05) {
      return { icon: '->', color: th.blue, text: 'Pure normalization: each spatial slice has zero mean and unit variance. Click cells to edit and watch mean/var update. Other slices stay unaffected!' };
    }
    return { icon: 'i', color: th.purple, text: `Gamma=${gamma.toFixed(1)} scales and beta=${beta.toFixed(1)} shifts the normalized values. This lets the network learn the optimal output distribution per channel.` };
  };

  const insight = getInsight();

  const CellGrid = ({ values, range, editable, sz }) => (
    <div style={{ display: 'grid', gridTemplateColumns: `repeat(2,${sz}px)`, gap: 2 }}>
      {values.map((row, r) => row.map((v, c) => (
        <div key={`${r}${c}`}
          onClick={editable ? (e) => editCell(r, c, e) : undefined}
          style={{
            width: sz, height: sz, display: 'flex', alignItems: 'center', justifyContent: 'center',
            background: valBg(v, range), borderRadius: 5, fontSize: sz > 50 ? 13 : 9,
            fontFamily: 'monospace', color: th.text, fontWeight: 600,
            cursor: editable ? 'pointer' : 'default',
            border: `1px solid ${th.border}`, transition: 'all 0.3s ease',
            userSelect: 'none',
          }}>
          {v.toFixed(sz > 50 ? 1 : 1)}
        </div>
      )))}
    </div>
  );

  return (
    <div style={{ background: th.bg, minHeight: '100vh', display: 'flex', justifyContent: 'center', padding: '14px 10px', fontFamily: "'Inter',-apple-system,sans-serif" }}>
      <div style={{ maxWidth: 560, width: '100%' }}>
        {/* Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}>
          <div>
            <div style={{ fontSize: 18, fontWeight: 700, color: th.text }}>Instance Normalization</div>
            <div style={{ fontSize: 11, color: th.muted, marginTop: 2 }}>Each (batch, channel) normalizes independently over spatial dims</div>
          </div>
          <button onClick={reset} style={{ background: th.surface, border: `1px solid ${th.border}`, color: th.muted, borderRadius: 8, padding: '6px 14px', cursor: 'pointer', fontSize: 12, fontFamily: 'inherit' }}>Reset</button>
        </div>

        {/* Slice selector overview */}
        <div style={{ display: 'flex', gap: 6, marginBottom: 14 }}>
          {[0, 1].map(b => [0, 1].map(c => {
            const active = sel[0] === b && sel[1] === c;
            const res = allResults[b][c];
            const mxo = Math.max(...res.output.flat().map(Math.abs), 0.1);
            return (
              <div key={`${b}${c}`} onClick={() => setSel([b, c])}
                style={{
                  flex: 1, padding: '6px 4px', borderRadius: 10, cursor: 'pointer',
                  background: active ? `${th.purple}18` : th.surface,
                  border: active ? `2px solid ${th.purple}` : `1px solid ${th.border}`,
                  transition: 'all 0.25s ease', textAlign: 'center',
                }}>
                <div style={{ fontSize: 9, color: active ? th.purple : th.dim, fontWeight: 600, marginBottom: 4 }}>
                  B{b}, Ch{c}
                </div>
                <div style={{ display: 'flex', justifyContent: 'center' }}>
                  <CellGrid values={res.output} range={mxo} sz={28} />
                </div>
                <div style={{ fontSize: 8, color: th.dim, marginTop: 3, fontFamily: 'monospace' }}>
                  m={res.mean.toFixed(1)} v={res.variance.toFixed(1)}
                </div>
              </div>
            );
          })).flat()}
        </div>

        {/* Main computation detail */}
        <div style={{ background: th.surface, borderRadius: 12, padding: 16, marginBottom: 10, border: `1px solid ${th.border}` }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
            <div style={{ fontSize: 13, fontWeight: 700, color: th.purple }}>
              Batch {sel[0]}, Channel {sel[1]}
            </div>
            <div style={{ fontSize: 10, color: th.dim, background: th.bg, padding: '3px 8px', borderRadius: 6 }}>
              Click cell +1 | Shift+click -1
            </div>
          </div>

          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 10 }}>
            {/* Input */}
            <div style={{ textAlign: 'center' }}>
              <div style={{ fontSize: 10, color: th.blue, fontWeight: 700, marginBottom: 5 }}>INPUT (H x W)</div>
              <CellGrid values={slice} range={maxIn} editable sz={58} />
            </div>

            {/* Arrow + stats */}
            <div style={{ textAlign: 'center', padding: '0 4px' }}>
              <svg width="60" height="90" viewBox="0 0 60 90">
                <defs>
                  <marker id="ah" markerWidth="8" markerHeight="6" refX="8" refY="3" orient="auto">
                    <path d="M0,0 L8,3 L0,6" fill={th.dim} />
                  </marker>
                </defs>
                <line x1="5" y1="45" x2="48" y2="45" stroke={th.dim} strokeWidth="1.5" markerEnd="url(#ah)" />
              </svg>
              <div style={{ fontSize: 10, fontFamily: 'monospace', color: th.muted, lineHeight: 1.9 }}>
                <div>mean = <span style={{ color: th.yellow, fontWeight: 700 }}>{result.mean.toFixed(2)}</span></div>
                <div>var = <span style={{ color: th.yellow, fontWeight: 700 }}>{result.variance.toFixed(2)}</span></div>
              </div>
            </div>

            {/* Output */}
            <div style={{ textAlign: 'center' }}>
              <div style={{ fontSize: 10, color: th.green, fontWeight: 700, marginBottom: 5 }}>OUTPUT</div>
              <CellGrid values={result.output} range={maxOut} sz={58} />
            </div>
          </div>

          {/* Formula */}
          <div style={{ textAlign: 'center', marginTop: 12, fontSize: 10, color: th.dim, fontFamily: 'monospace', background: th.bg, borderRadius: 6, padding: '6px 10px' }}>
            out = gamma * (x - {result.mean.toFixed(2)}) / sqrt({result.variance.toFixed(2)} + eps) + beta
          </div>
        </div>

        {/* Gamma / Beta */}
        <div style={{ background: th.surface, borderRadius: 12, padding: 14, marginBottom: 10, border: `1px solid ${th.border}` }}>
          <div style={{ display: 'flex', gap: 20 }}>
            <div style={{ flex: 1 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
                <span style={{ fontSize: 11, color: th.muted, fontWeight: 600 }}>gamma (scale)</span>
                <span style={{ fontSize: 13, fontFamily: 'monospace', color: th.yellow, fontWeight: 700 }}>{gamma.toFixed(2)}</span>
              </div>
              <input type="range" min="-2" max="3" step="0.05" value={gamma}
                onChange={e => setGamma(+e.target.value)}
                style={{ width: '100%', accentColor: th.yellow }} />
            </div>
            <div style={{ flex: 1 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
                <span style={{ fontSize: 11, color: th.muted, fontWeight: 600 }}>beta (shift)</span>
                <span style={{ fontSize: 13, fontFamily: 'monospace', color: th.pink, fontWeight: 700 }}>{beta.toFixed(2)}</span>
              </div>
              <input type="range" min="-3" max="3" step="0.05" value={beta}
                onChange={e => setBeta(+e.target.value)}
                style={{ width: '100%', accentColor: th.pink }} />
            </div>
          </div>
        </div>

        {/* Insight */}
        <div style={{
          background: `${insight.color}10`, borderRadius: 10, padding: 12,
          borderLeft: `3px solid ${insight.color}`, fontSize: 11, lineHeight: 1.7, color: th.muted,
        }}>
          <span style={{ color: insight.color, fontWeight: 700, marginRight: 6 }}>{insight.icon}</span>
          {insight.text}
        </div>
      </div>
    </div>
  );
}
